import { transliterate, type DevanagariLanguage } from './transliterate'
import { HistoryManager } from './history'

export interface NepaliIMEOptions {
    useDevanagariDigits?: boolean
    onStateChange?: (state: NepaliIMEState) => void
    enableHistory?: boolean
    maxHistory?: number
    language?: DevanagariLanguage
    enableExtendedRomanization?: boolean
    customWordMap?: Record<string, string>
}

export interface NepaliIMEState {
    romanBuffer: string[]
    currentWord: string
    output: string
    cursorPosition: number
}

const digitMap: Record<string, string> = {
    '0': '०', '1': '१', '2': '२', '3': '३', '4': '४',
    '5': '५', '6': '६', '7': '७', '8': '८', '9': '९',
}

/**
 * Headless Nepali IME Core
 * Framework-agnostic transliteration engine
 * Can be used with Vanilla JS, React, Vue, Svelte, etc.
 */
export class NepaliIMECore {
    private state: NepaliIMEState
    private options: Required<NepaliIMEOptions>
    private history: HistoryManager | null
    private convertedBuffer: string[]
    private committedOutput: string

    constructor(options: NepaliIMEOptions = {}) {
        this.options = {
            useDevanagariDigits: options.useDevanagariDigits ?? true,
            onStateChange: options.onStateChange ?? (() => { }),
            enableHistory: options.enableHistory ?? true,
            maxHistory: options.maxHistory ?? 100,
            language: options.language ?? 'generic',
            enableExtendedRomanization: options.enableExtendedRomanization ?? false,
            customWordMap: options.customWordMap ?? {},
        }
        this.state = {
            romanBuffer: [],
            currentWord: '',
            output: '',
            cursorPosition: 0,
        }
        this.convertedBuffer = []
        this.committedOutput = ''
        this.history = this.options.enableHistory
            ? new HistoryManager({ maxHistory: this.options.maxHistory })
            : null
    }

    /**
     * Get current state
     */
    public getState(): Readonly<NepaliIMEState> {
        return { ...this.state }
    }

    /**
     * Handle keyboard input
     * Returns true if the event was handled, false otherwise
     */
    public handleKey(key: string, modifiers: { ctrl?: boolean; alt?: boolean; meta?: boolean; shift?: boolean } = {}): boolean {
        // Handle undo/redo
        if (modifiers.ctrl || modifiers.meta) {
            if (key === 'z' && !(modifiers.alt || modifiers.ctrl && modifiers.meta)) {
                this.undo()
                return true
            }
            if ((key === 'y' || (key === 'z' && modifiers.shift)) && !(modifiers.alt)) {
                this.redo()
                return true
            }
        }

        // Allow modifier key combinations (except Backspace/Delete)
        if (modifiers.ctrl || modifiers.meta || modifiers.alt) {
            if (key !== 'Backspace' && key !== 'Delete') {
                return false
            }
        }

        // Navigation keys - let browser handle
        const navigationKeys = [
            'ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown',
            'Home', 'End', 'PageUp', 'PageDown',
            'Tab', 'Escape', 'Insert',
            'F1', 'F2', 'F3', 'F4', 'F5', 'F6', 'F7', 'F8', 'F9', 'F10', 'F11', 'F12',
            'CapsLock', 'NumLock', 'ScrollLock', 'Pause', 'PrintScreen',
            'ContextMenu', 'Meta', 'Control', 'Alt', 'Shift'
        ]

        if (navigationKeys.includes(key)) {
            return false
        }

        // Handle backspace and delete
        if (key === 'Backspace' || key === 'Delete') {
            this.deleteCharacter()
            this.updateOutput()
            this.pushHistory()
            return true
        }

        // Handle digits
        if (/^[0-9]$/.test(key)) {
            this.commitCurrentWord()
            const digit = this.options.useDevanagariDigits ? digitMap[key] : key
            this.pushSegment(digit)
            this.updateOutput()
            return true
        }

        // Handle punctuation (but NOT dot - dot is used for nukta sequences like kh., .r)
        if (this.isPunctuation(key)) {
            this.commitCurrentWord()
            const punct = key === '|' ? '।' : key
            this.pushSegment(punct)
            this.updateOutput()
            return true
        }

        // Handle space
        if (key === ' ') {
            this.commitCurrentWord()
            this.pushSegment(' ')
            this.updateOutput()
            return true
        }

        // Handle enter/newline
        if (key === 'Enter') {
            this.commitCurrentWord()
            this.pushSegment('\n')
            this.updateOutput()
            return true
        }

        // Handle letter input (including dot/apostrophe for nukta and accent sequences)
        if (/^[a-zA-Z~^`.'"]$/.test(key)) {
            this.state.currentWord += key
            this.updateOutput()
            this.pushHistory()
            return true
        }

        // Keep state in sync for any other printable character.
        // This prevents native DOM insertion from diverging from IME core state.
        if (key.length === 1) {
            this.commitCurrentWord()
            this.pushSegment(key)
            this.updateOutput()
            this.pushHistory()
            return true
        }

        return false
    }

    /**
     * Insert text (e.g., from paste)
     */
    public insertText(text: string): void {
        this.commitCurrentWord()
        this.pushSegment(text)
        this.updateOutput()
        this.pushHistory()
    }

    /**
     * Clear all content
     */
    public clear(): void {
        this.state.romanBuffer = []
        this.state.currentWord = ''
        this.convertedBuffer = []
        this.committedOutput = ''
        this.updateOutput()
    }

    /**
     * Set content directly (useful for framework integration)
     */
    public setValue(value: string): void {
        this.state.romanBuffer = []
        this.convertedBuffer = []
        this.committedOutput = ''
        if (value) {
            this.pushSegment(value)
        }
        this.state.currentWord = ''
        this.updateOutput()
    }

    /**
     * Get current output value
     */
    public getValue(): string {
        return this.state.output
    }

    /**
     * Update digit conversion setting
     */
    public setUseDevanagariDigits(value: boolean): void {
        this.options.useDevanagariDigits = value
        this.rebuildConvertedBuffer()
        this.updateOutput()
    }

    /**
     * Get digit conversion setting
     */
    public getUseDevanagariDigits(): boolean {
        return this.options.useDevanagariDigits
    }

    public setLanguage(language: DevanagariLanguage): void {
        this.options.language = language
        this.rebuildConvertedBuffer()
        this.updateOutput()
    }

    public getLanguage(): DevanagariLanguage {
        return this.options.language
    }

    // Private helper methods

    private commitCurrentWord(): void {
        if (this.state.currentWord) {
            this.pushSegment(this.state.currentWord)
            this.state.currentWord = ''
        }
    }

    private deleteCharacter(): void {
        if (this.state.currentWord.length > 0) {
            this.state.currentWord = this.state.currentWord.slice(0, -1)
        } else if (this.state.romanBuffer.length > 0) {
            const lastSegment = this.popSegment()
            if (!lastSegment) return
            if (lastSegment.length > 1) {
                this.pushSegment(lastSegment.slice(0, -1))
            }
        }
    }

    private isPunctuation(key: string): boolean {
        // Note: dot '.' is NOT punctuation - it's used for nukta sequences (kh., gh., .r, .l)
        return key === '|' || key === '!' || key === '?' || key === ',' || key === ';' || key === ':'
    }

    private convertSegment(segment: string): string {
        // Whitespace/punctuation - keep as is
        if (/^[\s।॥!?,;:\n]+$/.test(segment)) {
            return segment
        }
        // Already Nepali digits - keep as is
        if (/^[०-९]+$/.test(segment)) {
            return segment
        }
        // Romanized word - convert it
        return transliterate(segment, {
            useDevanagariDigits: this.options.useDevanagariDigits,
            language: this.options.language,
            enableExtendedRomanization: this.options.enableExtendedRomanization,
            customWordMap: this.options.customWordMap
        })
    }

    private updateOutput(): void {
        let output = this.committedOutput

        // Add current word being typed
        if (this.state.currentWord) {
            output += transliterate(this.state.currentWord, {
                useDevanagariDigits: this.options.useDevanagariDigits,
                language: this.options.language,
                enableExtendedRomanization: this.options.enableExtendedRomanization,
                customWordMap: this.options.customWordMap
            })
        }

        this.state.output = output
        this.state.cursorPosition = output.length

        // Notify listeners
        this.options.onStateChange(this.getState())
    }

    private pushSegment(segment: string): void {
        const converted = this.convertSegment(segment)
        this.state.romanBuffer.push(segment)
        this.convertedBuffer.push(converted)
        this.committedOutput += converted
    }

    private popSegment(): string | null {
        if (this.state.romanBuffer.length === 0) {
            return null
        }
        const raw = this.state.romanBuffer.pop()!
        const converted = this.convertedBuffer.pop() ?? ''
        if (converted.length > 0) {
            this.committedOutput = this.committedOutput.slice(0, -converted.length)
        }
        return raw
    }

    private rebuildConvertedBuffer(): void {
        this.convertedBuffer = []
        this.committedOutput = ''
        for (const segment of this.state.romanBuffer) {
            const converted = this.convertSegment(segment)
            this.convertedBuffer.push(converted)
            this.committedOutput += converted
        }
    }

    private pushHistory(): void {
        if (this.history) {
            this.history.push(this.state.output, this.state.cursorPosition)
        }
    }

    /**
     * Undo last change
     */
    public undo(): boolean {
        if (!this.history || !this.history.canUndo()) {
            return false
        }

        const state = this.history.undo()
        if (state) {
            this.setValue(state.value)
            return true
        }
        return false
    }

    /**
     * Redo last undone change
     */
    public redo(): boolean {
        if (!this.history || !this.history.canRedo()) {
            return false
        }

        const state = this.history.redo()
        if (state) {
            this.setValue(state.value)
            return true
        }
        return false
    }

    /**
     * Check if undo is available
     */
    public canUndo(): boolean {
        return this.history?.canUndo() ?? false
    }

    /**
     * Check if redo is available
     */
    public canRedo(): boolean {
        return this.history?.canRedo() ?? false
    }

    /**
     * Clear undo/redo history
     */
    public clearHistory(): void {
        this.history?.clear()
    }
}
